# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

import androidx.appcompat.app.AppCompatActivity
import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.util.Log

class MainActivity : AppCompatActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        val intent = intent
        if (Intent.ACTION_SEND == intent.action && intent.clipData != null || intent.clipData!!.itemsCount > 0) {
            val uri = (intent.clipData!!.items[0].uri)
            when(intent.type){
                "text/plain" -> {
                    // Handle text here
                    Log.d("Shared Text", intent.getStringExtra(Intent.EXTRA_TEXT).toString())
                }
                "image/*" -> {
                    // Handle image here
                    Log.d("Shared Image Uri", uri.toString())
                }
            }
        }
    }
}